+    #[test]
+    fn extreme_tick_counts() {
+        let mut sim = Simulation::new(42, SimConfig::fast());
+
+        // Advance many frames - should not panic or overflow
+        sim.tick_n(50000);
+        assert_eq!(sim.frame(), 50000);
+
+        // Frame counter should still be valid
+        sim.tick();
+        assert_eq!(sim.frame(), 50001);
