+    #[test]
+    fn alerts_have_valid_state() {
+        let mut sim = Simulation::new(42, SimConfig::fast());
+        sim.tick_n(200);
+
+        for alert in &sim.alerts {
+            // All alerts should have valid IDs
+            assert!(alert.id > 0);
